<script setup lang="ts">
const supabase=useSupabaseClient<any>(),state=ref<any>(null),message=ref('')
const institution=reactive({name:'Organizational execution institution',objective:'Evaluate and safely deliver the next highest-value capability'}),causal=reactive({intervention:'Adaptive capability routing',segment:'active operators',treatment_mean:1.18,control_mean:1,sample_size:100,federated:true}),treasury=reactive({capability:'proof-carrying routing',requested_budget_usd:1000,realized_roi:1.8,warranty_score:.95,opportunity_cost:100}),credential=reactive({claim_type:'verified_capability',claim_value:'connectors:admin',audience:'approved relying parties'}),incident=reactive({signal:'Provider reliability deviated from its warranty',severity:'high',capability:'remote-mcp'}),policy=ref('Connector scopes must be least-privilege and expire. Irreversible or over-budget actions require independent approval and a verified snapshot.')
async function authed<T>(url:string,options:any={}){const{data:{session}}=await supabase.auth.getSession();return $fetch<T>(url,{...options,headers:{...(session?.access_token?{authorization:`Bearer ${session.access_token}`}:{})}})}
async function load(){state.value=await authed('/api/constitution/context')}
async function act(action:string,values:any={}){message.value='';try{await authed('/api/constitution/action',{method:'POST',body:{action,values}});message.value=`${action.replaceAll('_',' ')} completed with a proof envelope.`;await load()}catch(e:any){message.value=e?.data?.message||e?.message||'Autonomy action failed.'}}
async function institutionAction(){if(!state.value?.autonomy?.institutions?.length)await act('establish_institution',{name:institution.name});else await act('institutional_case',{objective:institution.objective,institution_id:state.value.autonomy.institutions[0].id})}
onMounted(load)
</script>
<template><section id="constitutional-autonomy" class="mt-5 rounded-xl border border-violet-200 bg-white p-4" aria-labelledby="autonomy-heading"><div><div class="text-[10px] font-semibold uppercase tracking-[.14em] text-violet-700">Constitutional autonomy</div><h2 id="autonomy-heading" class="mt-1 text-sm font-semibold">Bounded intelligence that can explain, appeal, recover, and learn</h2><p class="mt-1 text-xs text-gray-500">Institutional roles, causal evidence, budgets, credentials, policies, continuity, and recovery remain proof-carrying and approval-aware.</p></div><div v-if="!state" class="mt-4 text-xs text-gray-400">Loading constitutional autonomy…</div><div v-else class="mt-4 grid gap-3 lg:grid-cols-2"><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Constitutional agent institution</h3><p class="mt-1 text-[10px] text-gray-500">Separate proposal, simulation, review, approval, execution, audit, and appeal.</p><input v-if="!state.autonomy.institutions.length" v-model="institution.name" class="mt-2 w-full rounded border p-2 text-xs"><textarea v-else v-model="institution.objective" rows="2" class="mt-2 w-full rounded border p-2 text-xs"/><button class="mt-2 rounded bg-violet-700 px-3 py-2 text-xs text-white" @click="institutionAction">{{state.autonomy.institutions.length?'Open separated-power case':'Establish institution'}}</button></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Causal outcome exchange</h3><div class="mt-2 grid grid-cols-2 gap-2"><input v-model="causal.intervention" class="col-span-2 rounded border p-2 text-xs"><input v-model.number="causal.treatment_mean" type="number" step=".01" aria-label="Treatment mean" class="rounded border p-2 text-xs"><input v-model.number="causal.control_mean" type="number" step=".01" aria-label="Control mean" class="rounded border p-2 text-xs"><input v-model.number="causal.sample_size" type="number" min="20" aria-label="Sample size" class="rounded border p-2 text-xs"><label class="flex items-center gap-2 text-[10px]"><input v-model="causal.federated" type="checkbox">Federated aggregate</label></div><button class="mt-2 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('causal_evidence',causal)">Record privacy-safe evidence</button></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Self-financing capability treasury</h3><input v-model="treasury.capability" class="mt-2 w-full rounded border p-2 text-xs"><div class="mt-2 grid grid-cols-2 gap-2"><input v-model.number="treasury.requested_budget_usd" type="number" aria-label="Requested budget" class="rounded border p-2 text-xs"><input v-model.number="treasury.realized_roi" type="number" step=".1" aria-label="Realized ROI" class="rounded border p-2 text-xs"></div><button class="mt-2 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('treasury_proposal',treasury)">Propose evidence-weighted allocation</button><p class="mt-2 text-[10px] text-gray-500">Proposal only; spending still requires an authorized approver.</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Selective-disclosure passport</h3><div class="mt-2 grid gap-2"><input v-model="credential.claim_type" class="rounded border p-2 text-xs"><input v-model="credential.claim_value" type="password" aria-label="Private claim" class="rounded border p-2 text-xs"><input v-model="credential.audience" class="rounded border p-2 text-xs"></div><button class="mt-2 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('selective_credential',credential)">Issue committed credential</button><p class="mt-2 text-[10px] text-gray-500">The private claim is committed with a nonce; its raw value is not stored.</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Incident immune system</h3><textarea v-model="incident.signal" rows="2" class="mt-2 w-full rounded border p-2 text-xs"/><div class="mt-2 grid grid-cols-2 gap-2"><select v-model="incident.severity" class="rounded border p-2 text-xs"><option>low</option><option>medium</option><option>high</option><option>critical</option></select><input v-model="incident.capability" class="rounded border p-2 text-xs"></div><button class="mt-2 rounded bg-amber-700 px-3 py-2 text-xs text-white" @click="act('immune_incident',incident)">Generate least-disruptive response</button><p class="mt-2 text-[10px] text-gray-500">Revocation, disabling, and rollback remain approval-gated.</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Natural-language policy compiler</h3><textarea v-model="policy" rows="4" class="mt-2 w-full rounded border p-2 text-xs"/><button class="mt-2 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('compile_policy',{source_text:policy})">Compile and contract-test policy</button><p v-if="state.autonomy.policies[0]" class="mt-2 text-[10px] text-emerald-700">Latest: {{state.autonomy.policies[0].test_result.passed}} tests passed · {{state.autonomy.policies[0].status}}</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Portable agent continuity capsule</h3><p class="mt-1 text-[10px] text-gray-500">Encrypted preferences, competencies, and commitments; no connector secrets or transferable permissions.</p><button class="mt-3 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('continuity_capsule')">Seal encrypted continuity capsule</button><p class="mt-2 text-[10px] text-gray-500">{{state.autonomy.capsules.length}} user-owned capsules</p></article><article class="rounded-xl border p-4"><h3 class="text-xs font-semibold">Adversarial journey swarm</h3><p class="mt-1 text-[10px] text-gray-500">Test stable destinations across roles, accessibility profiles, permission failures, expiry, latency, and connector faults.</p><button class="mt-3 rounded bg-gray-900 px-3 py-2 text-xs text-white" @click="act('adversarial_journeys',{deployment_url:'https://www.madeus.cc'})">Run adversarial contract matrix</button><p v-if="state.autonomy.journeys[0]" class="mt-2 text-[10px] text-emerald-700">Latest: {{state.autonomy.journeys[0].results.passed}}/{{state.autonomy.journeys[0].results.checks}} checks passed</p></article></div><p v-if="message" role="status" class="mt-3 rounded bg-violet-50 p-2 text-xs text-violet-800">{{message}}</p></section></template>
